#include <Servo.h>
#define TRIG 12
#define ECHO 11

Servo servo;

void setup() {
  pinMode(TRIG, OUTPUT);
  pinMode(ECHO, INPUT);
  servo.attach(10);
}

long readDistance() {
  digitalWrite(TRIG, LOW); delayMicroseconds(2);
  digitalWrite(TRIG, HIGH); delayMicroseconds(10);
  digitalWrite(TRIG, LOW);
  long duration = pulseIn(ECHO, HIGH);
  return duration * 0.034 / 2;
}

void loop() {
  long dist = readDistance();
  if (dist < 20) {
    // Stop & look around
    servo.write(45); delay(500);
    servo.write(135); delay(500);
    servo.write(90);
  }
}

