#include <Servo.h>
#define TRIG 2
#define ECHO 3

Servo servo;

void setup() {
  pinMode(TRIG, OUTPUT);
  pinMode(ECHO, INPUT);
  servo.attach(9);
  servo.write(0); // Lid closed
}

void loop() {
  digitalWrite(TRIG, HIGH); delayMicroseconds(10); digitalWrite(TRIG, LOW);
  long duration = pulseIn(ECHO, HIGH);
  long dist = duration * 0.034 / 2;

  if (dist < 15) {
    servo.write(90); // Open Lid
    delay(3000);
    servo.write(0);  // Close
  }
  delay(500);
}

#include <DHT.h>
#include <LiquidCrystal_I2C.h>

DHT dht(2, DHT22);
LiquidCrystal_I2C lcd(0x27, 16, 2);

void setup() {
  dht.begin();
  lcd.begin(16, 2);
  lcd.backlight();
}

void loop() {
  float t = dht.readTemperature();
  float h = dht.readHumidity();

  lcd.setCursor(0, 0);
  lcd.print("Temp: "); lcd.print(t); lcd.print(" C");
  lcd.setCursor(0, 1);
  lcd.print("Hum: "); lcd.print(h); lcd.print(" %");
  delay(2000);
}

