const int sensors[] = {A0, A1, A2};
const int relays[] = {2, 3, 4};

void setup() {
  for(int i=0; i<3; i++) pinMode(relays[i], OUTPUT);
}

void checkZone(int zone) {
  int val = analogRead(sensors[zone]);
  if (val > 750) {
    digitalWrite(relays[zone], HIGH); // Open valve
  } else {
    digitalWrite(relays[zone], LOW);  // Close valve
  }
}

void loop() {
  for(int i=0; i<3; i++) checkZone(i);
  delay(60000);
}

#include <Servo.h>
#include <LiquidCrystal_I2C.h>

Servo gate;
LiquidCrystal_I2C lcd(0x27, 16, 2);
int slots = 3;

void setup() {
  gate.attach(5); gate.write(0);
  lcd.begin(16,2); lcd.backlight();
}

void loop() {
  int s1 = digitalRead(2);
  int s2 = digitalRead(3);
  int s3 = digitalRead(4);
  int occupied = (s1==LOW) + (s2==LOW) + (s3==LOW);
  int free = slots - occupied;

  lcd.setCursor(0, 0);
  lcd.print("Free Slots: "); lcd.print(free);
  delay(500);
}

