#include <SoftwareSerial.h>
#include "VoiceRecognitionV3.h"

VR myVR(2, 3); // RX, TX
uint8_t records[7]; // save record list
uint8_t buf[64];

void setup() {
  myVR.begin(9600);
  pinMode(4, OUTPUT);
}

void loop() {
  int ret = myVR.recognize(buf, 50);
  if(ret > 0) {
    if (buf[1] == 0) { // Trained command 0
      digitalWrite(4, HIGH);
    } else if (buf[1] == 1) { // Command 1
      digitalWrite(4, LOW);
    }
  }
}

// Class energy saver - turns off load if no occupancy
unsigned long lastOccupiedTime = 0;

void setup() {
  pinMode(2, INPUT); // PIR
  pinMode(7, OUTPUT); // Fan
  pinMode(8, OUTPUT); // Light
}

void loop() {
  if (digitalRead(2) == HIGH) {
    lastOccupiedTime = millis();
    digitalWrite(7, HIGH); digitalWrite(8, HIGH);
  } else {
    if (millis() - lastOccupiedTime > 300000) { // 5 mins
      digitalWrite(7, LOW); digitalWrite(8, LOW); // Turn off
    }
  }
}
